import { Component, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { ProductService, ProductInput } from '../../core/services/product.service';

@Component({
  selector: 'app-admin-product-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './admin-product-form.component.html',
  styleUrl: './admin-product-form.component.css',
})
export class AdminProductFormComponent {
  private readonly fb = inject(FormBuilder);
  private readonly productService = inject(ProductService);
  private readonly route = inject(ActivatedRoute);
  private readonly router = inject(Router);

  readonly editId = signal<string | null>(null);
  readonly saving = signal<boolean>(false);
  readonly errorMessage = signal<string>('');

  form: FormGroup = this.fb.group({
    name: ['', [Validators.required]],
    description: ['', [Validators.required]],
    priceDollars: [0, [Validators.required, Validators.min(0)]],
    stockQty: [0, [Validators.required, Validators.min(0)]],
    imageUrl: [''],
  });

  ngOnInit(): void {
    const id = this.route.snapshot.paramMap.get('id');
    if (!id) return;
    this.editId.set(id);
    this.productService.get(id).subscribe({
      next: (p) =>
        this.form.patchValue({
          name: p.name,
          description: p.description,
          priceDollars: p.priceCents / 100,
          stockQty: p.stockQty,
          imageUrl: p.imageUrl ?? '',
        }),
      error: () => {},
    });
  }

  save(): void {
    if (this.form.invalid) return;
    this.saving.set(true);
    this.errorMessage.set('');
    const v = this.form.value;
    const input: ProductInput = {
      name: v.name,
      description: v.description,
      priceCents: Math.round(Number(v.priceDollars) * 100),
      stockQty: Number(v.stockQty),
      imageUrl: v.imageUrl?.trim() ? v.imageUrl.trim() : null,
    };
    const id = this.editId();
    const request$ = id
      ? this.productService.update(id, input)
      : this.productService.create(input);
    request$.subscribe({
      next: () => this.router.navigate(['/admin/products']),
      error: (err) => {
        this.saving.set(false);
        this.errorMessage.set(err?.error?.message ?? 'Could not save product.');
      },
    });
  }
}
